import { CSSResultArray, PropertyValues, isServer } from 'lit';
import { property } from 'lit/decorators.js';
import { queryAssignedElements } from 'lit/decorators/query-assigned-elements.js';

// styles
import { styles } from './styles/index.styles';

// components
import '@maersk-global/mds-components-core-button-group-item';

// types
import { McList } from '@maersk-global/mds-components-core-list';
import { ListTypes } from '@maersk-global/mds-components-core-list/src/lib/types';
import { IMcButtonGroup, IMcButtonGroupVariant } from './types';
import type { IMcButtonGroupItem } from '@maersk-global/mds-components-core-button-group-item/src/lib/types';

export type { IMcButtonGroup } from './types';

/**
 * A customizable button group component that combines individual buttons into a cohesive group.
 * Category: Forms, Content Display
 * Purpose: Combines individual buttons that have a logical relationship into a cohesive group.
 * When to use: Related actions, Toggle options, Navigation between views
 * When not to use: Single actions, Non-related buttons
 * Works with components: mc-button-group-item
 * Alternative component names: Button Set, Action Group, Toggle Group
 *
 * @element `mc-button-group`
 *
 * @event {CustomEvent<IMcListChangeDetail>} listchange - Emitted when a button group item is interacted.
 * @event {CustomEvent<IMcListItemsLoadedDetail>} listitemsloaded - Emitted when the button group items are loaded.
 * @event {CustomEvent<IMcListFocusChangeDetail>} focuschange - Emitted when a button group item receives focus.
 * @event {Event} scroll - Dispatched when the button group is scrolled.
 *
 * @slot - The default slot where the button group items go.
 *
 * @csspart `list` - for changing visuals of the inner list container.
 */
export class McButtonGroup extends McList implements IMcButtonGroup {
  @property({ type: String, reflect: true })
  public selectiontype: ListTypes = 'none';

  @property({ type: String, reflect: true })
  public variant: IMcButtonGroupVariant = 'bordered';

  @property({ type: String })
  public selectedappearance: 'primary' | 'neutral' = 'primary';

  @queryAssignedElements({ flatten: true })
  protected slottedElements!: Array<HTMLElement>;

  protected get buttonGroupItems(): Array<HTMLElement> {
    if (isServer) {
      return [];
    }
    return Array.from(this.querySelectorAll('mc-button-group-item'));
  }

  public static get styles(): CSSResultArray {
    return [super.styles, styles];
  }

  public constructor() {
    super();
    this.width = 'auto';
    this.disablecircularkeynav = true;
    this.keynavigationtype = 'tab';
    this.disablehandlemousemove = true;
    this.scrollToSelectedValue = true;
    this.orientation = 'horizontal';
  }

  protected firstUpdated(changedProperties: PropertyValues): void {
    super.firstUpdated(changedProperties);
    this.noborder = this.variant === 'borderless' || this.variant === 'rounded';
    this.updateChildrenPropsAndAttr();
  }

  protected willUpdate(changedProperties: PropertyValues): void {
    super.willUpdate(changedProperties);

    if (changedProperties.has('selectiontype')) {
      this.type = this.selectiontype;
    }
    if (changedProperties.has('variant')) {
      this.noborder = this.variant === 'borderless' || this.variant === 'rounded';
      this.buttonGroupItems.forEach((item) => {
        (item as IMcButtonGroupItem).variant = this.variant;
      });
    }
    if (changedProperties.has('selectedappearance')) {
      this.buttonGroupItems.forEach((item) => {
        (item as IMcButtonGroupItem).selectedappearance = this.selectedappearance;
      });
    }
  }

  private updateChildrenPropsAndAttr() {
    this.buttonGroupItems.forEach((item, index) => {
      (item as IMcButtonGroupItem).variant = this.variant;
      (item as IMcButtonGroupItem).selectedappearance = this.selectedappearance;
      item.setAttribute('orientation', this.orientation);

      if (index === 0) {
        item.setAttribute('position', 'first');
      }
      if (index === this.buttonGroupItems.length - 1) {
        item.setAttribute('position', 'last');
      }
    });
  }
}
customElements.get('mc-button-group') || customElements.define('mc-button-group', McButtonGroup);
